/**
 * Email notification handler — formats and sends email notifications
 * for order lifecycle events.
 *
 * Integrates with the existing notification architecture using BOTH patterns:
 * - EventBus subscription for order:created events
 * - CallbackRegistry for order:status-changed events
 *
 * This mirrors the approach used in NotificationService, keeping the
 * codebase consistent (even though the mixed pattern is acknowledged
 * as something to unify in the future).
 *
 * Depends on:
 * - EventBus (event system) for order:created events
 * - CallbackRegistry (direct callbacks) for order:status-changed events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notifications.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern),
   * matching the existing NotificationService approach.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
      )
      .join('');

    const itemLines = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Your order <strong>${event.order.id}</strong> has been placed successfully.</p>
<table><tr><th>Item</th><th>Qty</th><th>Price</th></tr>${itemRows}</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Your order ${event.order.id} has been placed successfully.

Items:
${itemLines}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Handle order status change — send status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const newStatusLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const previousStatusLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> status has been updated.</p>
<p>Status: <em>${previousStatusLabel}</em> &rarr; <strong>${newStatusLabel}</strong></p>`;

    const textBody = `Order Status Update

Your order ${event.order.id} status has been updated.

Status: ${previousStatusLabel} -> ${newStatusLabel}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${event.order.id} — ${newStatusLabel}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send an email (in-memory for this demo).
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get sent emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-handler.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    handler = new EmailNotificationHandler(eventBus);
  });

  describe('order:created email', () => {
    it('should send confirmation email on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include HTML and text versions', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      // HTML body should contain HTML tags and item details
      expect(email.htmlBody).toContain('<h1>Order Confirmation</h1>');
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
      // Text body should contain plain text version
      expect(email.textBody).toContain('Order Confirmation');
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('$20.00');
    });

    it('should include user name in email body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 5 },
          ],
          total: 5,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Hi Bob');
      expect(email.textBody).toContain('Hi Bob');
    });

    it('should include all items in confirmation email', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
    });
  });

  describe('order:status-changed email', () => {
    it('should send status update email on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.subject).toContain('Confirmed');
    });

    it('should include previous and new status in email body', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Confirmed');
      expect(email.htmlBody).toContain('Shipped');
      expect(email.textBody).toContain('Confirmed');
      expect(email.textBody).toContain('Shipped');
    });

    it('should handle delivered status', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [],
          total: 50,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Delivered');
      expect(email.textBody).toContain('Shipped');
      expect(email.textBody).toContain('Delivered');
    });

    it('should handle cancelled status', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-3',
          userId: 'user-3',
          items: [],
          total: 30,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Cancelled');
    });
  });

  describe('email management', () => {
    it('should count sent emails', () => {
      expect(handler.getEmailCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear emails', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getEmailCount()).toBe(1);
      handler.clearEmails();
      expect(handler.getEmailCount()).toBe(0);
    });
  });
});

